public static long solve(long[] landStartTime, long[] landDuration, long[] waterStartTime, long[] waterDuration) {
    long minTime = Long.MAX_VALUE;

    for (int i = 0; i < landStartTime.length; i++) {
        for (int j = 0; j < waterStartTime.length; j++) {
            // Case 1: land first, then water
            long landStart = landStartTime[i];
            long landEnd = landStart + landDuration[i];
            long waterStart = Math.max(waterStartTime[j], landEnd);
            long waterEnd = waterStart + waterDuration[j];
            minTime = Math.min(minTime, waterEnd);

            // Case 2: water first, then land
            waterStart = waterStartTime[j];
            waterEnd = waterStart + waterDuration[j];
            landStart = Math.max(landStartTime[i], waterEnd);
            landEnd = landStart + landDuration[i];
            minTime = Math.min(minTime, landEnd);
        }
    }

    return minTime;
}
